#include <stdio.h>
#include <string.h>

typedef struct {
    int pid;
    char name[16];
    float cpu;
    int mem_kb;
} ProcInfo;

int format_proc_row(char *buf, size_t size, const ProcInfo *proc) {
    return snprintf(buf, size, "%4d|%-10s|%6.1f|%8d",
                    proc->pid, proc->name, proc->cpu, proc->mem_kb);
}

int main(void) {
    {
        char buf[64];
        ProcInfo proc = {1, "init", 0.1f, 2048};
        format_proc_row(buf, sizeof(buf), &proc);
        printf("%d\n", (strstr(buf, "1") != NULL) ? 1 : 0);
        printf("%d\n", (strstr(buf, "init") != NULL) ? 1 : 0);
    }
    {
        char buf[64];
        ProcInfo proc = {42, "bash", 1.5f, 8192};
        format_proc_row(buf, sizeof(buf), &proc);
        printf("%d\n", (strstr(buf, "42") != NULL) ? 1 : 0);
        printf("%d\n", (strstr(buf, "bash") != NULL) ? 1 : 0);
    }
    {
        char buf[64];
        ProcInfo proc = {1337, "gcc", 95.2f, 524288};
        format_proc_row(buf, sizeof(buf), &proc);
        printf("%d\n", (strstr(buf, "1337") != NULL) ? 1 : 0);
        printf("%d\n", (strstr(buf, "gcc") != NULL) ? 1 : 0);
    }
    {
        char buf[64];
        ProcInfo proc = {1, "init", 0.1f, 2048};
        format_proc_row(buf, sizeof(buf), &proc);
        /* Should be exactly: "   1|init      |   0.1|    2048" */
        printf("%s\n", buf);
    }
    return 0;
}

